function searchMatrix(matrix, rows, cols, target) {
    let left = 0, right = rows * cols - 1;

    while (left <= right) {
        let mid = Math.floor(left + (right - left) / 2);
        let midValue = matrix[Math.floor(mid / cols)][mid % cols];

        if (midValue === target) {
            return true;
        } else if (midValue < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return false;
}

// Input handling
const input = require("readline").createInterface({
    input: process.stdin,
    output: process.stdout
});

let matrix = [];
let N, M, target, count = 0;

input.on("line", (line) => {
    if (count === 0) {
        [N, M] = line.split(" ").map(Number);
        count++;
    } else if (count <= N) {
        matrix.push(line.split(" ").map(Number));
        count++;
    } else {
        target = parseInt(line);
        if (searchMatrix(matrix, N, M, target)) {
            console.log("YES");
        } else {
            console.log("NO");
        }
        input.close();
    }
});
